```class Solution {
public:
    int flipLights(int n, int presses) {
        int result = 0;
        for (int i = 0; i < presses; i++) {
            int bulb_status = 1;
            for (int j = 0; j < n; j++) {
                bulb_status ^= (1 << j);
            }
            result += bulb_status;
        }
        return result;
    }
};
